To parse formulas that reference other formulas, you can use a technique called memoization. This involves caching the results of expensive function calls so that they can be reused instead of recalculated.

Here's an example of how you can implement this in Python:

```python
class Formula:
    def __init__(self, name, formula):
        self.name = name
        self.formula = formula

    def __str__(self):
        return self.formula

    def evaluate(self, values):
        return eval(self.formula, values)


class FormulaParser:
    def __init__(self):
        self.formulas = {}

    def register_formula(self, name, formula):
        self.formulas[name] = Formula(name, formula)

    def lookup(self, name):
        return self.formulas.get(name)

    def parse_formula(self, formula):
        # Replace formula names with their values
        for name, value in self.formulas.items():
            formula = formula.replace(name, str(value.evaluate({})))

        return formula


