Smart enumerations, also known as enumeration classes or enum classes, are a design pattern used in Domain-Driven Design (DDD) to encapsulate the behavior and validation rules associated with an enumeration.

Here's an example of how to implement smart enumerations in C#:

```csharp
public abstract class EnumBase<T>
{
    public abstract T Value { get; }

    public override string ToString()
    {
        return Value.ToString();
    }

    public override int GetHashCode()
    {
        return Value.GetHashCode();
    }

    public override bool Equals(object obj)
    {
        if (obj is EnumBase<T> enumObj)
        {
            return Value.Equals(enumObj.Value);
        }
        return false;
    }
}

public class Color : EnumBase<Color>
{
